import React, { useRef, useEffect, useCallback, useState } from 'react';
import { Engine, MSE_CAPABLE, probeStream } from './VideoEngine';
import { AudioEngine, AUDIO_MSE_CAPABLE } from './AudioEngine';

// ── A/V Sync constants ────────────────────────────────────────────────────────
const DRIFT_HARD_S = 0.15;
const DRIFT_SOFT_S = 0.05;
const SYNC_MS      = 250;

// ── A/V Sync controller ───────────────────────────────────────────────────────
class AVSync {
  constructor(video, audio) {
    this.video   = video;
    this.audio   = audio;
    this._timer  = null;
    this._paused = false;
  }

  start() {
    this._active = true;
    this.stop();
    this._timer = setInterval(() => this._tick(), SYNC_MS);
    this.video.addEventListener('seeked',  this._onSeeked);
    this.audio.addEventListener('waiting', this._onAudioWaiting);
    this.video.addEventListener('waiting', this._onVideoWaiting);
  }

  stop() {
    this._active = false;
    clearInterval(this._timer);
    this._timer = null;
    this.video.removeEventListener('seeked',  this._onSeeked);
    this.audio.removeEventListener('waiting', this._onAudioWaiting);
    this.video.removeEventListener('waiting', this._onVideoWaiting);
  }

  _tick() {
    const { video: v, audio: a } = this;
    if (!v || !a || v.paused || a.paused || this._paused) return;
    const drift = v.currentTime - a.currentTime;
    if (Math.abs(drift) > DRIFT_HARD_S) {
      try { a.currentTime = v.currentTime; } catch {}
    } else if (Math.abs(drift) > DRIFT_SOFT_S) {
      try { a.playbackRate = drift > 0 ? 1.03 : 0.97; } catch {}
    } else {
      if (a.playbackRate !== 1.0) try { a.playbackRate = 1.0; } catch {}
    }
  }

  _onSeeked = () => {
    const { video: v, audio: a } = this;
    if (!v || !a) return;
    a.currentTime = v.currentTime;
  };

  _onAudioWaiting = () => {
    const { video: v, audio: a } = this;
    if (!v || !a || this._paused) return;
    this._paused = true;
    v.pause();
    const resume = () => {
      if (!this._active) { this._paused = false; return; }
      this._paused = false;
      try { a.currentTime = v.currentTime; } catch {}
      Promise.all([v.play(), a.play()]).catch(() => {});
    };
    a.addEventListener('canplay', resume, { once: true });
  };

  _onVideoWaiting = () => {
    const { video: v, audio: a } = this;
    if (!v || !a || this._paused) return;
    this._paused = true;
    a.pause();
    const resume = () => {
      if (!this._active) { this._paused = false; return; }
      this._paused = false;
      try { a.currentTime = v.currentTime; } catch {}
      Promise.all([v.play(), a.play()]).catch(() => {});
    };
    v.play().catch(() => {});
    v.addEventListener('canplay', resume, { once: true });
  };
}

// ── Global audio singleton ────────────────────────────────────────────────────
let _currentAudio = null;
function stopCurrentAudio() {
  if (!_currentAudio) return;
  const { audio, sync } = _currentAudio;
  if (sync) sync.stop();
  audio.pause();
  _currentAudio = null;
}

// ── Component ─────────────────────────────────────────────────────────────────
const VideoAudioPlayer = ({ src, audioSrc: audioSrcProp, id, activeAudioId, onVisibilityChange }) => {
  const videoRef    = useRef(null);
  const audioRef    = useRef(null);
  const boxRef      = useRef(null);
  const engRef      = useRef(null);
  const audioEngRef = useRef(null);
  const syncRef     = useRef(null);
  const [mode, setMode] = useState(null);

  const isActive = activeAudioId === id;
  const audioSrc = audioSrcProp || null;

  // ── Probe once per src ────────────────────────────────────────────────────
  useEffect(() => {
    if (!MSE_CAPABLE) { setMode(false); return; }
    let live = true;
    probeStream(src).then(ok => { if (live) setMode(ok); });
    return () => { live = false; };
  }, [src]);

  // ── Bootstrap video ───────────────────────────────────────────────────────
  useEffect(() => {
    if (mode === null) return;
    const video = videoRef.current;
    if (!video) return;

    if (mode) {
      const eng = new Engine(video, src);
      engRef.current = eng;

      const onErr  = () => { eng.destroy(); engRef.current = null; setMode(false); };
      const onTime = () => eng.onTime();
      const onSeek = () => eng.onSeek();

      video.addEventListener('error',      onErr, { once: true });
      video.addEventListener('timeupdate', onTime);
      video.addEventListener('seeking',    onSeek);

      eng.start().then(() => { video.play().catch(() => {}); });

      return () => {
        video.removeEventListener('error',      onErr);
        video.removeEventListener('timeupdate', onTime);
        video.removeEventListener('seeking',    onSeek);
        eng.destroy();
        engRef.current = null;
      };
    } else {
      video.src = src;
      video.play().catch(() => {});
      return () => { video.src = ''; };
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [mode, src]);

  // ── Bootstrap audio MSE ───────────────────────────────────────────────────
  useEffect(() => {
    const audio = audioRef.current;
    if (!audio || !audioSrc || !AUDIO_MSE_CAPABLE) return;
    const eng = new AudioEngine(audio, audioSrc);
    audioEngRef.current = eng;
    const onTime = () => eng.onTime();
    audio.addEventListener('timeupdate', onTime);
    eng.start().catch(() => {});
    return () => {
      audio.removeEventListener('timeupdate', onTime);
      eng.destroy();
      audioEngRef.current = null;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [audioSrc]);

  // ── A/V sync ──────────────────────────────────────────────────────────────
  useEffect(() => {
    const v = videoRef.current;
    const a = audioRef.current;
    if (!v || !a) return;

    if (isActive) {
      if (!audioSrc) return;
      let cancelled = false;
      const startSync = () => {
        if (cancelled) return;
        stopCurrentAudio();
        try { a.currentTime = v.currentTime; } catch {}
        const sync = new AVSync(v, a);
        syncRef.current = sync;
        _currentAudio = { audio: a, sync };
        sync.start();
        a.play().catch(() => {});
      };
      if (a.readyState >= 2) {
        startSync();
      } else {
        a.addEventListener('canplay', startSync, { once: true });
      }
      return () => {
        cancelled = true;
        a.removeEventListener('canplay', startSync);
        if (syncRef.current) { syncRef.current.stop(); syncRef.current = null; }
        if (_currentAudio && _currentAudio.audio === a) {
          a.pause();
          _currentAudio = null;
        }
      };
    } else {
      a.pause();
      if (_currentAudio && _currentAudio.audio === a) _currentAudio = null;
      if (syncRef.current) { syncRef.current.stop(); syncRef.current = null; }
    }
  }, [isActive]);

  // ── Intersection observer ─────────────────────────────────────────────────
  const handleVisibility = useCallback(
    ([entry]) => onVisibilityChange(id, entry.isIntersecting && entry.intersectionRatio > 0.5),
    [id, onVisibilityChange]
  );

  useEffect(() => {
    const el = boxRef.current;
    if (!el) return;
    const obs = new IntersectionObserver(handleVisibility, { threshold: 0.5 });
    obs.observe(el);
    return () => obs.disconnect();
  }, [handleVisibility]);

  return (
    <div ref={boxRef} style={{ overflowAnchor: 'none' }}>
      <video
        ref={videoRef}
        autoPlay
        muted
        playsInline
        style={{ width: '100%', height: 'auto', display: 'block' }}
      />
      <audio
        ref={audioRef}
        loop
        preload={AUDIO_MSE_CAPABLE ? 'none' : 'auto'}
        {...(!AUDIO_MSE_CAPABLE && audioSrc && { src: audioSrc })}
        style={{ position: 'absolute', left: '-9999px' }}
        tabIndex="-1"
      />
    </div>
  );
};

export default VideoAudioPlayer;
